4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies (underpopulation) — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent live cells both die (underpopulation, 1 neighbor each) — [(0,1), (1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("block still life remains unchanged — [(0,0),(1,0),(0,1),(1,1)] → same 4 cells", () => {
15	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result).toHaveLength(4);
18	    expect(result).toEqual(expect.arrayContaining(block));
19	  });
20	  it("live cell with > 3 neighbors dies (overpopulation) — center of full 3x3 dies", () => {
21	    const full3x3: Cell[] = [
22	      [0, 0], [1, 0], [2, 0],
23	      [0, 1], [1, 1], [2, 1],
24	      [0, 2], [1, 2], [2, 2],
25	    ];
26	    const result = nextGeneration(full3x3);
27	    expect(result).not.toEqual(expect.arrayContaining([[1, 1]]));
28	  });
29	  it("dead cell with exactly 3 live neighbors becomes alive (reproduction)", () => {
30	    const lShape: Cell[] = [[0, 0], [1, 0], [0, 1]];
31	    const result = nextGeneration(lShape);
32	    expect(result).toEqual(expect.arrayContaining([[1, 1]]));
33	  });
34	  it("live cell with 2 neighbors survives (survival rule, middle of 3-in-a-row)", () => {
35	    const row: Cell[] = [[0, 0], [0, 1], [0, 2]];
36	    const result = nextGeneration(row);
37	    expect(result).toEqual(expect.arrayContaining([[0, 1]]));
38	  });
39	  it("blinker oscillates: vertical to horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
40	    const vertical: Cell[] = [[0, 0], [0, 1], [0, 2]];
41	    const result = nextGeneration(vertical);
42	    expect(result).toHaveLength(3);
43	    expect(result).toEqual(expect.arrayContaining<Cell>([[-1, 1], [0, 1], [1, 1]]));
44	  });
45	  it("handles negative coordinates — block at negative coords stays still", () => {
46	    const block: Cell[] = [[-5, -5], [-4, -5], [-5, -4], [-4, -4]];
47	    const result = nextGeneration(block);
48	    expect(result).toHaveLength(4);
49	    expect(result).toEqual(expect.arrayContaining(block));
50	  });
51	});
